/// A simple UUID v4 generator using Dart's Random class.
/// Generates RFC 4122 compliant version 4 UUIDs.
class UUIDGenerator {
  static final Random _random = Random.secure();

  /// Generates a single UUID v4 string.
  /// Format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
  /// where x is any hex digit and y is one of 8, 9, a, or b.
  static String generateV4() {
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Set version to 4 (0100 in binary) — high nibble of byte 6
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary) — high bits of byte 8
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatAsUUID(bytes);
  }

  /// Generates a time-based UUID using timestamp + random bits.
  /// Not strictly UUID v1, but useful for sortable offline IDs.
  static String generateTimeBased() {
    final now = DateTime.now().microsecondsSinceEpoch;
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Embed timestamp in the first 6 bytes
    bytes[0] = (now >> 40) & 0xFF;
    bytes[1] = (now >> 32) & 0xFF;
    bytes[2] = (now >> 24) & 0xFF;
    bytes[3] = (now >> 16) & 0xFF;
    bytes[4] = (now >> 8) & 0xFF;
    bytes[5] = now & 0xFF;

    // Set version nibble to indicate custom time-based (we use 7 as a marker)
    bytes[6] = (bytes[6] & 0x0F) | 0x70;

    // Set variant to RFC 4122
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatAsUUID(bytes);
  }

  /// Generates a short ID (not a full UUID) for compact offline use.
  static String generateShortId({int length = 12}) {
    const chars = '0123456789abcdef';
    return List.generate(length, (_) => chars[_random.nextInt(chars.length)])
        .join();
  }

  /// Formats 16 bytes as a UUID string: 8-4-4-4-12
  static String _formatAsUUID(List<int> bytes) {
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    return '${hex.substring(0, 8)}-'
        '${hex.substring(8, 12)}-'
        '${hex.substring(12, 16)}-'
        '${hex.substring(16, 20)}-'
        '${hex.substring(20, 32)}';
  }

  /// Validates whether a string is a valid UUID format.
  static bool isValidUUID(String uuid) {
    final regex = RegExp(
      r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
      caseSensitive: false,
    );
    return regex.hasMatch(uuid);
  }
}

